/* ── Shared Element Transition ────────────────────────────────────────────
   The named element morphs automatically — the browser interpolates
   position, size, and shape. We define what happens to everything else.
   ──────────────────────────────────────────────────────────────────────── */

/* The morphing element — smooth geometry interpolation */
::view-transition-group(shared-element) {
  animation-duration: 0.4s;
  animation-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
  overflow: clip;
}

::view-transition-old(shared-element),
::view-transition-new(shared-element) {
  animation: none;
  mix-blend-mode: normal;
  width: 100%;
  height: 100%;
}

/* Disable the default whole-page cross-fade */
::view-transition-old(root) {
  animation: segue-shared-fade-out 0.2s ease forwards;
}

::view-transition-new(root) {
  animation: segue-shared-fade-in 0.35s ease 0.15s both;
}

@keyframes segue-shared-fade-in {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes segue-shared-fade-out {
  from { opacity: 1; }
  to   { opacity: 0; }
}

/* Accessibility — respect reduced motion preference */
@media (prefers-reduced-motion: reduce) {
  ::view-transition-group(shared-element) {
    animation-duration: 0.01ms;
  }

  ::view-transition-old(root),
  ::view-transition-new(root) {
    animation-duration: 0.01ms;
  }
}

"use client"

import { useRouter } from "next/navigation"
import { MouseEvent, ReactNode, useRef } from "react"
import "./transition.css"

const DEFAULT_TRANSITION_NAME = "shared-element"

interface SharedCardProps {
  href: string
  children: ReactNode
  className?: string
  transitionName?: string
}

function waitForTarget(name: string, timeout = 3000): Promise<void> {
  return new Promise((resolve) => {
    if (document.querySelector(`[data-shared-target="${name}"]`)) {
      resolve()
      return
    }

    const observer = new MutationObserver(() => {
      if (document.querySelector(`[data-shared-target="${name}"]`)) {
        observer.disconnect()
        resolve()
      }
    })

    observer.observe(document.documentElement, {
      childList: true,
      subtree: true,
    })

    setTimeout(() => {
      observer.disconnect()
      resolve()
    }, timeout)
  })
}

export function SharedCard({
  href,
  children,
  className,
  transitionName = DEFAULT_TRANSITION_NAME,
}: SharedCardProps) {
  const router = useRouter()
  const ref = useRef<HTMLDivElement>(null)

  const handleClick = (e: MouseEvent<HTMLDivElement>) => {
    e.preventDefault()

    if (!document.startViewTransition) {
      router.push(href)
      return
    }

    const el = ref.current
    if (el) {
      el.style.viewTransitionName = transitionName
    }

    const transition = document.startViewTransition(async () => {
      if (el) {
        el.style.viewTransitionName = ""
      }
      router.push(href)
      await waitForTarget(transitionName)
    })

    transition.finished.finally(() => {
      if (el) {
        el.style.viewTransitionName = ""
      }
    })
  }

  return (
    <div
      ref={ref}
      onClick={handleClick}
      className={className}
      style={{ cursor: "pointer" }}
    >
      {children}
    </div>
  )
}

